  1	import { type FC, type Ref, useMemo, useState } from 'react';
  2	import useProviderInventory from 'src/modules/Providers/hooks/useProviderInventory';
  3	
  4	import type {
  5	  OpenShiftNetworkAttachmentDefinition,
  6	  V1beta1PlanSpecTransferNetwork,
  7	  V1beta1Provider,
  8	} from '@kubev2v/types';
  9	import {
 10	  Dropdown,
 11	  DropdownItem,
 12	  DropdownList,
 13	  MenuToggle,
 14	  type MenuToggleElement,
 15	} from '@patternfly/react-core';
 16	import { useForkliftTranslation } from '@utils/i18n';
 17	
 18	import { PROVIDER_DEFAULTS } from './utils/constants';
 19	import { getNetworkName } from './utils/utils';
 20	
 21	type TransferNetworkDropdownProps = {
 22	  provider: V1beta1Provider;
 23	  value: V1beta1PlanSpecTransferNetwork | null;
 24	  onChange: (val: V1beta1PlanSpecTransferNetwork | null) => void;
 25	};
 26	
 27	const TransferNetworkDropdown: FC<TransferNetworkDropdownProps> = ({
 28	  onChange,
 29	  provider,
 30	  value,
 31	}) => {
 32	  const { t } = useForkliftTranslation();
 33	  const [isOpen, setIsOpen] = useState(false);
 34	  const { inventory: networks } = useProviderInventory<OpenShiftNetworkAttachmentDefinition[]>({
 35	    provider,
 36	    subPath: 'networkattachmentdefinitions?detail=4',
 37	  });
 38	
 39	  const transferNetworks: V1beta1PlanSpecTransferNetwork[] = useMemo(
 40	    () =>
 41	      (networks ?? []).map((network) => ({
 42	        apiVersion: network.object.apiVersion,
 43	        kind: network.object.kind,
 44	        name: network.name,
 45	        namespace: network.namespace,
 46	        uid: network.uid,
 47	      })),
 48	    [networks],
 49	  );
 50	
 51	  const dropdownItems = [
 52	    <DropdownItem
 53	      key="default"
 54	      description={t("Use the provider's default transfer network")}
 55	      onClick={() => {
 56	        onChange(null);
 57	      }}
 58	    >
 59	      {PROVIDER_DEFAULTS}
 60	    </DropdownItem>,
 61	    ...transferNetworks.map((network) => (
 62	      <DropdownItem
 63	        key={`${network.namespace}/${network.name}`}
 64	        description={network.namespace}
 65	        onClick={() => {
 66	          onChange(network);
 67	        }}
 68	      >
 69	        {network.name}
 70	      </DropdownItem>
 71	    )),
 72	  ];
 73	
 74	  return (
 75	    <Dropdown
 76	      isOpen={isOpen}
 77	      onOpenChange={setIsOpen}
 78	      onSelect={() => {
 79	        setIsOpen(false);
 80	      }}
 81	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
 82	        <MenuToggle
 83	          ref={toggleRef}
 84	          onClick={() => {
 85	            setIsOpen(!isOpen);
 86	          }}
 87	          isExpanded={isOpen}
 88	          variant="default"
 89	        >
 90	          {getNetworkName(value)}
 91	        </MenuToggle>
 92	      )}
 93	      shouldFocusToggleOnSelect
 94	      popperProps={{ position: 'right' }}
 95	      isScrollable
 96	    >
 97	      <DropdownList>{dropdownItems}</DropdownList>
 98	    </Dropdown>
 99	  );
100	};
101	
102	export default TransferNetworkDropdown;

